traits.code:
pub trait App
{
   fn init(&mut self, ctx: &mut InitContext);
   fn event(&mut self, e: AppEvent, ctx: &mut UpdateContext);
   fn draw(&mut self, r: &mut RenderContext);
}

pub trait Platform
{
   fn run<T: App + 'static>(&self, app: T) -> !;
   fn request_redraw(&self) -> ();
   fn set_high_refresh(&self, enable: bool) -> ();
   fn set_idle_timer_disabled(&self, disabled: bool) -> ();
   fn clipboard_get(&self) -> Option<String>;
   fn clipboard_set(&self, s: &str) -> ();
   fn ime_show(&self) -> ();
   fn ime_hide(&self) -> ();
   fn permissions(&self) -> &dyn Permissions;
   fn camera(&self) -> &dyn CameraManager;
   fn bluetooth(&self) -> &dyn Bluetooth;
   fn push(&self) -> &dyn PushManager;
   fn capabilities(&self) -> Capabilities;
}

pub trait Renderer
{
   fn device_caps(&self) -> DeviceCaps;
   fn begin_frame(&mut self, fb: &FrameTarget) -> FrameToken;
   fn encode_pass(&mut self, list: &DrawList) -> ();
   fn submit(&mut self, token: FrameToken) -> ();
   fn resize(&mut self, w: u32, h: u32, scale: f32) -> ();
}

pub fn run_app<T: App + 'static>(target: MobileTarget, app: T) -> !
{
   // dispatch to platform-specific runner
}

