   pub platform: Box<dyn Platform>,
}

pub struct UpdateContext
{
   pub post_task: Box<dyn Fn(Box<dyn FnOnce() + Send>) + Send + Sync>,
   pub timers: Timers,
   pub haptics: Box<dyn Haptics>,
}
impl UpdateContext
{
   #[cfg(feature = "tokio-runtime")]
   pub fn spawn<F>(&self, fut: F) -> ()
   where F: core::future::Future<Output = ()> + Send + 'static
   {
      /* engine-provided */
   }
}
