}

pub struct DeviceCaps
{
   pub max_framerate_hz: u32,
   pub supports_edr: bool,
   pub supports_msaa4x: bool,
   pub native_scale: f32,
   pub color_space: ColorSpace, // see ColorSpace
   pub a11y_reduce_motion: bool,
}
