{
   Srgb,
   DisplayP3Linear,
   ScRGBLinear,
   Bt2020PQ
}
pub enum AppEvent
{
   Lifecycle(Lifecycle),
   Window(WindowEvent),
   Input(InputEvent),
   Text(TextEvent),
}
bitflags::bitflags!
{
   pub struct Capabilities: u64
   {
      const CAMERA          = 1 << 0;
      const BLUETOOTH       = 1 << 1;
      const PUSH            = 1 << 2;
      const HOVER_POINTER   = 1 << 3;
      const MOTION          = 1 << 4;
   }
}
pub enum Lifecycle { WillEnterForeground, DidEnterBackground, WillTerminate }

pub enum WindowEvent
{
   Resized { w: u32, h: u32, scale: f32, safe: Insets },
   OrientationChanged { portrait: bool }
}

pub enum InputEvent
{
   Touch(TouchEvent),
   Pointer(PointerEvent),
