pub enum PermissionDomain { Notifications, Location, Camera, Contacts, Bluetooth, Motion }
pub enum PermissionStatus { NotDetermined, Denied, Limited, Authorized }
pub trait Permissions
{
   fn request(&self, domain: PermissionDomain) -> ();
   fn status(&self, domain: PermissionDomain) -> PermissionStatus;
   fn subscribe<F: Fn(PermissionDomain, PermissionStatus) + Send + 'static>(&self, f: F) -> ();
}
pub type PeripheralId = u128;

#[derive(Clone, Copy)]
pub struct BleUuid(pub [u8; 16]);

pub struct PeripheralInfo
{
   pub id: PeripheralId, pub name: Option<String>, pub rssi_dbm: i16
}

pub struct GattChar
{
   pub service: BleUuid, pub characteristic: BleUuid
}

pub enum BluetoothEvent
{
   StateChanged { powered_on: bool },
   Discovered(PeripheralInfo),
   Connected(PeripheralId),
   Disconnected(PeripheralId),
   Notified { id: PeripheralId, chr: GattChar, data: Vec<u8> },
}

pub trait Bluetooth
{
   // Central role
   fn powered_on(&self) -> bool;
   fn subscribe_events<F: Fn(BluetoothEvent) + Send + 'static>(&self, f: F) -> ();
   fn start_scan(&self, services: &[BleUuid]) -> ();
   fn stop_scan(&self) -> ();
   fn connect(&self, id: PeripheralId) -> ();
   fn disconnect(&self, id: PeripheralId) -> ();
   fn read(&self, id: PeripheralId, chr: GattChar) -> Result<Vec<u8>, PlatformError>;
   fn write(&self, id: PeripheralId, chr: GattChar, data: &[u8], with_response: bool) -> Result<(), PlatformError>;
   fn notify(&self, id: PeripheralId, chr: GattChar, enable: bool) -> Result<(), PlatformError>;

   // Peripheral role
   fn advertise_start(&self, name: &str, services: &[BleUuid]) -> ();
   fn advertise_stop(&self) -> ();
}
