}

pub trait PushManager
{
   fn register(&self) -> ();
   fn device_token(&self) -> Option<PushToken>;
   fn subscribe<F: Fn(PushNotification) + Send + 'static>(&self, f: F) -> ();
   fn set_badge(&self, count: i32) -> ();
   fn clear_badge(&self) -> ();
}
