{
   pub device: CameraDevice, // Front or Back
   pub fps: u32,             // hint
   pub resolution: (u32, u32) // hint
}
pub enum CameraDevice { Front, Back }
pub struct CameraFrame { pub tex: ImageHandle, pub size: (u32,u32), pub timestamp_ns: u64, pub rotation_deg: u16 }
pub trait CameraStream { fn stop(&self) -> (); }
pub trait CameraManager
{
   fn start_stream<F>(&self, cfg: CameraConfig, on_frame: F) -> Box<dyn CameraStream>
      where F: Fn(CameraFrame) + Send + 'static;
}

pub type AnimId = u64;

pub enum EaseKind
{
   Linear, QuadIn, QuadOut, QuadInOut, CubicIn, CubicOut, CubicInOut, BackInOut, ElasticOut, BounceOut
}

pub struct Ease
{
   pub kind: EaseKind
}

pub struct SpringParams
{
   pub stiffness: f32, pub damping: f32, pub mass: f32, pub eps: f32
}

pub enum AnimCurve
{
   Ease { ease: Ease },
   Spring { sp: SpringParams }
}

pub enum AnimProp
{
   Opacity,
   Transform2D,   // tx, ty, sx, sy, rot_rad
   ColorRGBA,
   CornerRadius,
   ShadowAlpha
}

pub struct Transform2D
{
   pub tx: f32, pub ty: f32, pub sx: f32, pub sy: f32, pub rot_rad: f32
}

pub enum AnimValue
{
   F32(f32),
   Vec2([f32; 2]),
   Vec4([f32; 4]),
   Mat3([f32; 9]),
   Xform2D(Transform2D)
}

pub enum Repeat
{
   Once,
   Count(u32),
   Forever
}

pub struct AnimDesc
{
   pub id: AnimId,
   pub prop: AnimProp,
   pub from: AnimValue,
   pub to: AnimValue,
   pub curve: AnimCurve,
   pub duration_ms: u32,
   pub delay_ms: u32,
   pub repeat: Repeat
}

impl UpdateContext
{
   pub fn anim_start(&mut self, desc: AnimDesc) -> AnimId { /* engine-provided */ }
   pub fn anim_cancel(&mut self, id: AnimId) -> () { /* engine-provided */ }
   pub fn anim_cancel_prop(&mut self, prop: AnimProp) -> () { /* engine-provided */ }
}

pub enum FitPolicy { Contain, Cover }

pub struct CanvasMetrics
{
   pub design_w: f32, pub design_h: f32,
   pub scale: f32, pub offset_x: f32, pub offset_y: f32,
   pub device_scale: f32
}

// Helper to compute canonical canvas transform
pub fn compute_canvas(view_w: f32, view_h: f32, design_w: f32, design_h: f32, device_scale: f32, fit: FitPolicy) -> CanvasMetrics
{
   let sx = view_w / design_w; let sy = view_h / design_h;
   let s = match fit { FitPolicy::Contain => sx.min(sy), FitPolicy::Cover => sx.max(sy) };
   let ox = ((view_w - design_w * s) * 0.5).floor(); let oy = ((view_h - design_h * s) * 0.5).floor();
   CanvasMetrics { design_w, design_h, scale: s, offset_x: ox, offset_y: oy, device_scale }
}

