pub trait RenderEncoder
{
   fn set_viewport(&mut self, vp: RectF) -> ();
   fn set_clip(&mut self, scissor: RectI) -> ();
   fn draw_solid(&mut self, verts: &[Vertex], color: Color) -> ();
   fn draw_image(&mut self, img: ImageHandle, dst: RectF, src: RectF) -> ();
   fn draw_rrect(&mut self, rect: RectF, radii: [f32; 4], color: Color) -> ();
   fn draw_nine_slice(&mut self, img: ImageHandle, rect: RectF, slice: Insets, alpha: f32) -> ();
   fn draw_backdrop(&mut self, rect: RectF, sigma: f32, tint: Color, alpha: f32) -> ();
   fn draw_spinner(&mut self, center: [f32;2], radius: f32, thickness: f32, phase: f32, alpha: f32) -> ();
   fn draw_glyph_run(&mut self, run: &GlyphRun) -> ();
}

section.code:
use oxideui::prelude::*;

struct Demo;

impl App for Demo
{
   fn init(&mut self, _ctx: &mut InitContext) { }

   fn event(&mut self, _e: AppEvent, _ctx: &mut UpdateContext) { }

   fn draw(&mut self, r: &mut RenderContext)
   {
      let mut enc = &mut *r.encoder;
      enc.set_viewport(RectF::new(0.0, 0.0, 400.0, 800.0));
      let verts = vec![
         Vertex { x: 10.0, y: 10.0 }, Vertex { x: 390.0, y: 10.0 }, Vertex { x: 200.0, y: 300.0 }
      ];
      enc.draw_solid(&verts, Color::rgba(0.2, 0.6, 0.9, 1.0));
   }
}

fn main()
{
   run_app(MobileTarget::Ios, Demo);
}
